52	func (f *CommandFactory) runSkillsCheck(cmd *cobra.Command, args []string) error {
53		paths := args
54		if len(paths) == 0 {
55			paths = f.defaultSkillCheckPaths()
56		}
57	
58		files, issues := skills.ValidatePaths(paths)
59		for _, issue := range issues {
60			_, _ = fmt.Fprintf(cmd.ErrOrStderr(), "skill issue: %s\n", issue.Error())
61		}
62		if len(issues) > 0 {
63			return NewExitError(ExitCodeGeneralError, fmt.Sprintf("skill validation failed with %d issue(s)", len(issues)))
64		}
65	
66		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "validated %d skill files\n", len(files))
67		return nil
68	}
