70	func (f *CommandFactory) defaultSkillCheckPaths() []string {
71		projectRoot := gitpkg.FindProjectRoot(f.WorkingDir)
72		if projectRoot == "" {
73			projectRoot = f.WorkingDir
74		}
75	
76		candidates := []string{
77			filepath.Join(projectRoot, "skills"),
78			filepath.Join(projectRoot, ".agents", "skills"),
79			filepath.Join(projectRoot, ".claude", "skills"),
80			filepath.Join(projectRoot, ".ddx", "plugins", "ddx"),
81			filepath.Join(projectRoot, "cli", "internal", "skills"),
82		}
83	
84		var paths []string
85		for _, candidate := range candidates {
86			if _, err := os.Stat(candidate); err == nil {
87				paths = append(paths, candidate)
88			}
89		}
90		return paths
91	}

